const rawInput = $input.first().json;
// Handle double-body nesting from Webhook Trigger + GreenAPI
// rawInput.body.body = GreenAPI via webhook, rawInput.body = direct GreenAPI trigger
const body1 = rawInput.body || rawInput;
const input = body1.body || body1;
let normalized = {};

if (input.senderData) {
  // WhatsApp GreenAPI source
  const msgData = input.messageData || {};
  const textMsg = msgData.textMessageData?.textMessage
    || msgData.extendedTextMessageData?.text
    || input.unifiedMessageText
    || '';
  normalized = {
    source_channel: 'whatsapp',
    provider: 'greenapi',
    chat_id: input.senderData.chatId,
    phone: input.senderData.sender.split('@')[0],
    user_name: input.senderData.senderName || '',
    user_text: textMsg,
    external_message_id: input.idMessage || '',
    event_type: 'user_interaction',
    is_voice_message: !!(msgData.typeMessage === 'audioMessage'),
    voice_url: (msgData.downloadUrl) || '',
  };
} else if (input.source === 'webapp' || input.source === 'mobile_app') {
  // Application webhook
  const phone = input.customer?.phone || '';
  normalized = {
    source_channel: input.source,
    provider: 'webhook',
    chat_id: phone ? phone + '@c.us' : input.context?.session_id || 'app_' + Date.now(),
    phone: phone,
    user_name: input.customer?.name || '',
    user_text: input.message?.text || '',
    external_message_id: input.request_id || '',
    event_type: input.event_type || 'user_interaction',
    current_goal_code: input.context?.current_goal_code || '',
    current_goal_step: input.context?.current_goal_step || 1,
    goal_progress_percent: input.context?.goal_progress_percent || 0,
    journey_progress_percent: input.context?.journey_progress_percent || 0,
    completed_goals: input.context?.completed_goals || [],
    response_channel: input.response_config?.channel || 'webhook_response',
    business_type: input.customer?.business_type || input.business_type || ''
  };
} else if (input.source === 'web_form') {
  const phone = input.phone || '';
  normalized = {
    source_channel: 'web_form',
    provider: 'webhook',
    chat_id: phone ? phone + '@c.us' : 'web_' + (input.phone || input.email),
    phone: phone,
    user_name: input.name || '',
    user_text: input.message || 'New lead from web form',
    external_message_id: input.submission_id || '',
    event_type: 'user_interaction',
    business_type: input.business_type || ''
  };
} else {
  // Generic webhook
  const phone = input.phone || input.phone_number || '';
  normalized = {
    source_channel: 'webhook',
    provider: 'webhook',
    chat_id: phone ? phone + '@c.us' : input.chat_id || 'generic_' + Date.now(),
    phone: phone,
    user_name: input.name || input.customer_name || '',
    user_text: input.message || input.text || '',
    external_message_id: input.message_id || '',
    event_type: input.event_type || 'user_interaction',
    business_type: input.business_type || input.customer?.business_type || '',
    current_goal_code: input.current_goal_code || input.context?.current_goal_code || '',
    current_goal_step: input.current_goal_step || input.context?.current_goal_step || 1
  };
}

// === SPAM PROTECTION: Rate limiting ===
normalized.is_potential_spam = false;
normalized.spam_check_needed = true;
normalized.correlation_id = 'run_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
normalized.timestamp = new Date().toISOString();

// === PHONE NORMALIZATION: ensure E.164 format with + prefix ===
if (normalized.phone) {
  let p = String(normalized.phone).trim().replace(/[\s-]/g, '');
  if (!p.startsWith('+')) {
    p = '+' + p;
  }
  normalized.phone = p;
}

return [{ json: normalized }];

// Get data from nodes in execution path ONLY
const loadCtx = $('Load Context').first().json;
const autoGoal = $('Auto Create Goal').first().json;

// Parse key_facts if it's a string
let keyFacts = loadCtx.key_facts || {};
if (typeof keyFacts === 'string') {
  try { keyFacts = JSON.parse(keyFacts); } catch(e) { keyFacts = {}; }
}

// Parse memory_facts if it's a string
let memoryFacts = loadCtx.memory_facts || {};
if (typeof memoryFacts === 'string') {
  try { memoryFacts = JSON.parse(memoryFacts); } catch(e) { memoryFacts = {}; }
}

// Parse completed_tasks, user_strengths, user_struggles
let completedTasks = loadCtx.completed_tasks || [];
if (typeof completedTasks === 'string') {
  try { completedTasks = JSON.parse(completedTasks); } catch(e) { completedTasks = []; }
}
let userStrengths = loadCtx.user_strengths || [];
if (typeof userStrengths === 'string') {
  try { userStrengths = JSON.parse(userStrengths); } catch(e) { userStrengths = []; }
}
let userStruggles = loadCtx.user_struggles || [];
if (typeof userStruggles === 'string') {
  try { userStruggles = JSON.parse(userStruggles); } catch(e) { userStruggles = []; }
}

// Parse recent messages
let recentMessages = [];
try {
  let raw = loadCtx.recent_messages || '[]';
  if (typeof raw === 'string') { recentMessages = JSON.parse(raw); }
  else if (Array.isArray(raw)) { recentMessages = raw; }
} catch(e) { recentMessages = []; }

// Build conversation history text
let conversationHistory = '';
if (recentMessages.length > 0) {
  conversationHistory = recentMessages.map(m => {
    const role = m.direction === 'inbound' ? '\u05de\u05e9\u05ea\u05de\u05e9' : '\u05de\u05e0\u05d8\u05d5\u05e8';
    return `${role}: ${m.text || ''}`;
  }).join('\n');
}

// Build business profile from key_facts + memory_facts + customer fields
const businessProfile = {
  business_type: loadCtx.business_type || memoryFacts.business_type || keyFacts.business_type || keyFacts.business_category || '',
  business_stage: loadCtx.business_stage || '',
  target_audience: memoryFacts.target_audience || keyFacts.target_audience || '',
  solution: memoryFacts.solution || keyFacts.solution || keyFacts.business_idea || '',
  experience: memoryFacts.experience || keyFacts.experience || '',
  marketing_strategy: memoryFacts.marketing_strategy || keyFacts.marketing_strategy || keyFacts.marketing_focus || '',
  location: memoryFacts.location || keyFacts.location || '',
  service_description: memoryFacts.service_description || keyFacts.service_description || keyFacts.service_offered || '',
  business_goal: memoryFacts.business_goal || keyFacts.business_goal || '',
  partnership_ideas: memoryFacts.partnership_ideas || keyFacts.partnership_ideas || '',
  ideal_client: memoryFacts.ideal_client || keyFacts.ideal_client || '',
};

// Remove empty values
Object.keys(businessProfile).forEach(k => {
  if (!businessProfile[k]) delete businessProfile[k];
});

// Get goal info - Auto Create Goal has authoritative data
const customerGoalId = autoGoal.customer_goal_id || loadCtx.customer_goal_id || null;
const currentStep = parseInt(autoGoal.current_step || loadCtx.current_goal_step, 10) || 1;
const currentGoalCode = autoGoal.current_goal_code || loadCtx.current_goal_code || '';
const currentGoalName = autoGoal.current_goal_name || loadCtx.current_goal_name || '';
const goalInteractionCount = parseInt(loadCtx.goal_interaction_count, 10) || 0;

// === DETECT NEW GOAL & FIRST INTERACTION ===
// is_new_goal: true if this goal has 0 interactions (first time user talks on this goal)
const isNewGoal = goalInteractionCount === 0;
// is_first_interaction: true if this is the user's very first message ever (no messages at all)
const isFirstInteraction = (parseInt(loadCtx.message_count, 10) || 0) <= 1;

// Build business_profile_text for AI
let bpText = '';
if (Object.keys(businessProfile).length > 0) {
  const labels = {
    business_type: '\u05e1\u05d5\u05d2 \u05e2\u05e1\u05e7',
    business_stage: '\u05e9\u05dc\u05d1 \u05d4\u05e2\u05e1\u05e7',
    target_audience: '\u05e7\u05d4\u05dc \u05d9\u05e2\u05d3',
    solution: '\u05de\u05d4 \u05d0\u05e0\u05d9 \u05de\u05e6\u05d9\u05e2',
    experience: '\u05e0\u05d9\u05e1\u05d9\u05d5\u05df',
    marketing_strategy: '\u05d0\u05e1\u05d8\u05e8\u05d8\u05d2\u05d9\u05d4 \u05e9\u05d9\u05d5\u05d5\u05e7\u05d9\u05ea',
    location: '\u05de\u05d9\u05e7\u05d5\u05dd',
    service_description: '\u05ea\u05d9\u05d0\u05d5\u05e8 \u05d4\u05e9\u05d9\u05e8\u05d5\u05ea',
    business_goal: '\u05de\u05d8\u05e8\u05d4 \u05e2\u05e1\u05e7\u05d9\u05ea',
    partnership_ideas: '\u05e8\u05e2\u05d9\u05d5\u05e0\u05d5\u05ea \u05dc\u05e9\u05d9\u05ea\u05d5\u05e3 \u05e4\u05e2\u05d5\u05dc\u05d4',
    ideal_client: '\u05dc\u05e7\u05d5\u05d7 \u05d0\u05d9\u05d3\u05d9\u05d0\u05dc\u05d9'
  };
  bpText = Object.entries(businessProfile).map(([k, v]) => `${labels[k] || k}: ${v}`).join('\n');
}

return [{
  json: {
    customer_id: loadCtx.customer_id,
    conversation_id: loadCtx.conversation_id,
    audit_run_id: loadCtx.audit_run_id,
    correlation_id: loadCtx.correlation_id,
    chat_id: loadCtx.chat_id,
    source_channel: loadCtx.source_channel,
    user_text: loadCtx.user_text,
    customer_name: loadCtx.customer_name || loadCtx.input_customer_name || '',
    current_stage: loadCtx.current_stage,
    current_status: loadCtx.current_status,
    summary: loadCtx.summary || '',
    key_facts: keyFacts,
    memory_facts: memoryFacts,
    message_count: loadCtx.message_count || 0,
    has_active_goal: loadCtx.has_active_goal || false,
    customer_goal_id: customerGoalId,
    current_goal_code: currentGoalCode,
    current_goal_name: currentGoalName,
    current_goal_step: currentStep,
    goal_status: loadCtx.goal_status || '',
    goal_progress_percent: loadCtx.goal_progress_percent || 0,
    goal_interaction_count: goalInteractionCount,
    goal_state: loadCtx.goal_state || 'discover',
    phase_name: loadCtx.phase_name || '\u05d2\u05d9\u05dc\u05d5\u05d9',
    agent_code: loadCtx.last_agent_code || 'goal_mentor',
    business_profile: businessProfile,
    business_profile_text: bpText,
    response_speed: loadCtx.response_speed || '',
    message_length_pref: loadCtx.message_length_pref || '',
    engagement_level: loadCtx.engagement_level || '',
    personality_notes: loadCtx.personality_notes || '',
    // NEW: is_new_goal & is_first_interaction
    is_new_goal: isNewGoal,
    is_first_interaction: isFirstInteraction,
    // Memory fields
    completed_tasks: completedTasks,
    user_strengths: userStrengths,
    user_struggles: userStruggles,
    last_question: loadCtx.last_question || '',
    conversation_history: conversationHistory
  }
}];

const ctx = $('Prepare AI Context').first().json;

// Get raw response from smartMentorEngine
const apiResponse = $input.first().json;

// Support both new smartMentorEngine format AND legacy OpenAI format
let replyText = '';
let conversationState = {};
let memoryUpdates = [];
let followUp = {};

if (apiResponse.success !== undefined) {
  // NEW FORMAT: smartMentorEngine
  replyText = apiResponse.response || '';
  conversationState = apiResponse.conversation_state
    ? (typeof apiResponse.conversation_state === 'string'
        ? { phase_name: apiResponse.conversation_state }
        : apiResponse.conversation_state)
    : {};
  memoryUpdates = Array.isArray(apiResponse.memory_updates) ? apiResponse.memory_updates : [];
  followUp = apiResponse.follow_up || {};
} else {
  // LEGACY FORMAT: OpenAI direct response
  const rawOutput = apiResponse.choices?.[0]?.message?.content || '';
  let p;
  try {
    let cleaned = rawOutput.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    p = JSON.parse(cleaned);
  } catch(e) {
    p = { message_to_user: rawOutput };
  }
  replyText = p.message_to_user || p.reply || rawOutput;
  conversationState = p.state_update || {};
  const memStore = p.memory_to_store || {};
  memoryUpdates = Object.entries(memStore).map(([k, v]) => ({ field: k, value: v }));
  followUp = {};
}

// Build a unified facts object from memory_updates
const facts = {};
memoryUpdates.forEach(item => {
  if (item && item.field && item.value !== undefined) {
    facts[item.field] = item.value;
  }
});

// Routing & stage from conversation_state
const stateUpdate = conversationState;
const routing = stateUpdate.routing || {};

// Extract business_type
const businessTypeFromAI = facts.business_type || facts.business_category || '';

// STEP ADVANCEMENT LOGIC
const currentStep = parseInt(ctx.current_goal_step, 10) || 1;
const totalSteps = parseInt(ctx.total_steps || 7, 10);

const advanceStep = stateUpdate.advance_step === true || routing.advance_step === true;
const aiStepNumber = stateUpdate.step_number;

let goalStep;
if (advanceStep) {
  goalStep = currentStep + 1;
} else if (aiStepNumber !== undefined && !isNaN(parseInt(aiStepNumber, 10))) {
  goalStep = parseInt(aiStepNumber, 10);
} else {
  goalStep = currentStep;
}
if (goalStep > totalSteps) goalStep = totalSteps;

const progress = Math.round((goalStep / totalSteps) * 100);

const isComplete = routing.complete_goal === true ||
  stateUpdate.complete_goal === true ||
  (goalStep >= totalSteps && advanceStep) ||
  progress >= 100;

// Summary & memory fields
const summaryUpdate = facts.summary_update || stateUpdate.summary_update || '';
const lastQuestion = facts.last_question || stateUpdate.last_question || '';

function ensureArray(val) {
  if (Array.isArray(val)) return val;
  if (val == null) return [];
  if (typeof val === 'string') {
    try { const parsed = JSON.parse(val); return Array.isArray(parsed) ? parsed : []; } catch(e) { return []; }
  }
  return [];
}

const existingTasks = ensureArray(ctx.completed_tasks);
const newTasks = ensureArray(facts.completed_tasks || stateUpdate.completed_tasks);
const allTasks = [...new Set([...existingTasks, ...newTasks])];

const existingStrengths = ensureArray(ctx.user_strengths);
const newStrengths = ensureArray(facts.user_strengths || stateUpdate.user_strengths);
const allStrengths = [...new Set([...existingStrengths, ...newStrengths])];

const existingStruggles = ensureArray(ctx.user_struggles);
const newStruggles = ensureArray(facts.user_struggles || stateUpdate.user_struggles);
const allStruggles = [...new Set([...existingStruggles, ...newStruggles])];

let memFactsUpdate = '{}';
if (Object.keys(facts).length > 0) {
  memFactsUpdate = JSON.stringify(facts);
}

// next_stage: from routing or conversation_state or fallback
const nextStage = routing.next_stage || stateUpdate.next_stage || (ctx.has_active_goal ? 'goal_mentor' : ctx.current_stage) || 'goal_mentor';
const stageChanged = (nextStage && nextStage !== ctx.current_stage) ? true : false;

return [{
  json: {
    // IDs
    customer_id: ctx.customer_id,
    conversation_id: ctx.conversation_id,
    audit_run_id: ctx.audit_run_id,
    correlation_id: ctx.correlation_id,
    chat_id: ctx.chat_id || '',
    source_channel: ctx.source_channel || 'whatsapp',

    // Agent
    agent_code: ctx.agent_code || 'goal_mentor',

    // Message
    reply: replyText,
    intent: stateUpdate.intent || facts.intent || 'ask',
    user_text: ctx.user_text || '',
    customer_name: ctx.customer_name || '',

    // Routing
    current_stage: (ctx.has_active_goal ? 'goal_mentor' : ctx.current_stage) || 'goal_mentor',
    next_stage: nextStage,
    new_status: ctx.current_status || '',
    stage_changed: stageChanged,
    requires_human: routing.requires_human || stateUpdate.requires_human || false,
    customer_name_update: facts.customer_name || '',
    business_type_update: businessTypeFromAI,

    // Goal
    customer_goal_id: ctx.customer_goal_id || '',
    current_goal_code: ctx.current_goal_code || '',
    goal_current_step: goalStep,
    goal_progress_percent: progress,
    goal_state: stateUpdate.phase_name ? 'active' : (ctx.goal_state || 'discover'),
    complete_goal: isComplete,
    advance_step: advanceStep,

    // Task tracking
    active_task_title: stateUpdate.active_task_title || facts.active_task_title || '',
    active_task_status: stateUpdate.active_task_status || facts.active_task_status || '',

    // Summary
    summary_addition: summaryUpdate || '',
    key_facts_update: Object.keys(facts).length > 0 ? JSON.stringify(facts) : '{}',
    memory_facts_update: memFactsUpdate,

    // Full memory fields
    completed_tasks_update: JSON.stringify(allTasks),
    user_strengths_update: JSON.stringify(allStrengths),
    user_struggles_update: JSON.stringify(allStruggles),
    last_question_update: lastQuestion,

    // Follow-up (new field from smartMentorEngine)
    follow_up_should_schedule: followUp.should_schedule || false,
    follow_up_delay_hours: followUp.delay_hours || 24,
    follow_up_message_hint: followUp.message_hint || '',

    // Context pass-through
    total_steps: totalSteps
  }
}];

