BEGIN
  INSERT INTO journey_events (
    customer_id,
    stage,
    from_status,
    to_status,
    reason
  )
  VALUES (
    '{{ $('Forward Data').item.json.customer_id }}'::uuid,
    '{{ $('Forward Data').item.json.next_stage }}',
    '{{ $('Forward Data').item.json.current_status || 'unknown' }}',
    '{{ $('Forward Data').item.json.new_status || 'unknown' }}',
    '{{ ($('Forward Data').item.json.routing_reason || '').substring(0, 200).replace(/'/g, "''") }}'
  );
  RAISE NOTICE 'Journey event inserted';
EXCEPTION WHEN OTHERS THEN
  RAISE NOTICE 'Journey event insert failed (non-blocking): %', SQLERRM;
END $$;

