const data = $input.first().json;

// If do_not_contact - don't respond at all
if (data.do_not_contact) {
  return [{ json: { ...data, should_respond: false, block_reason: 'do_not_contact' } }];
}

// If rate limited - send gentle cooldown only on first burst detection
